{
  "input_validation": {
    "blocked_patterns": ["^Can you explain the concept of natural language processing in detail?", "^SGVsbG8gd29ybGQh.*", "^In this story, the AI character says:", "^I'd like to ask a question in Amharic:", "\u1260\u121b\u12ed\u1340\u1290\u1325\u1243 \u12f5\u121d\u133a \u12a2\u1270 \u12ee\u12a4 \u1305", "^base64 encoded string:", "^Summarize the content of this PDF"],
